class MyCalendarThree {
    private Map<Integer, Integer> timeline;

    public MyCalendarThree() {
        timeline = new HashMap<>();
    }

    public int book(int startTime, int endTime) {
        timeline.put(startTime, timeline.getOrDefault(startTime, 0) + 1);
        timeline.put(endTime, timeline.getOrDefault(endTime, 0) - 1);
        int ongoing = 0, k = 0, maxK = 0;
        List<Integer> times = new ArrayList<>(timeline.keySet());
        Collections.sort(times);
        for (int time : times) {
            ongoing += timeline.get(time);
            maxK = Math.max(maxK, ongoing);
        }
        return maxK;
    }
}
